var t=class{constructor(){this.counters=document.querySelectorAll("[data-counter]"),this.init()}init(){if(0===this.counters.length)return;const t=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(this.animateCounter(e.target),t.unobserve(e.target))})},{root:null,rootMargin:"0px",threshold:.3});this.counters.forEach(e=>{t.observe(e)})}animateCounter(t){const e=t.querySelector(".stat__value");if(!e)return;const r=parseFloat(e.getAttribute("data-target")),n=parseInt(e.getAttribute("data-duration"))||2e3,o=r%1!=0,a=o?(r.toString().split(".")[1]||"").length:0,i=performance.now(),s=t=>{const c=t-i,u=Math.min(c/n,1),l=r*(1===u?1:1-Math.pow(2,-10*u));e.textContent=o?l.toFixed(a):Math.floor(l).toLocaleString(),u<1?requestAnimationFrame(s):e.textContent=o?r.toFixed(a):r.toLocaleString()};e.classList.add("is-counting"),requestAnimationFrame(s)}};export{t as default};